import React from 'react';
import { LightBulbIcon, ShieldCheckIcon, UserGroupIcon } from '@heroicons/react/24/outline';

const SafetyIndicators = () => {
  const stats = [
    { label: 'Street Lighting', value: '92%', icon: LightBulbIcon, color: 'text-yellow-500' },
    { label: 'Safe Zone Score', value: 'High', icon: ShieldCheckIcon, color: 'text-green-500' },
    { label: 'Crowd Density', value: 'Moderate', icon: UserGroupIcon, color: 'text-blue-500' },
  ];

  return (
    <div className="grid grid-cols-3 gap-4">
      {stats.map((stat, index) => (
        <div key={index} className="flex flex-col items-center p-3 rounded-2xl bg-white/50 border border-gray-100 text-center">
          <stat.icon className={`h-6 w-6 mb-2 ${stat.color}`} />
          <span className="text-xs font-semibold text-gray-400 uppercase tracking-tighter">{stat.label}</span>
          <span className="text-lg font-bold text-gray-800">{stat.value}</span>
        </div>
      ))}
    </div>
  );
};

export default SafetyIndicators;
